  1	import { type FC, useState } from 'react';
  2	
  3	import {
  4	  Button,
  5	  ButtonVariant,
  6	  DataList,
  7	  DataListAction,
  8	  DataListCell,
  9	  DataListItem,
 10	  DataListItemCells,
 11	  DataListItemRow,
 12	  Tooltip,
 13	} from '@patternfly/react-core';
 14	import { MinusCircleIcon, PlusCircleIcon } from '@patternfly/react-icons';
 15	import { isEmpty } from '@utils/helpers';
 16	
 17	import './InputList.style.css';
 18	
 19	type InputListRow<T> = FC<{ value: T; onChange: (value: T) => void }>;
 20	type InputListItem<T> = { id: string; content: T };
 21	
 22	let idCounter = 0;
 23	
 24	/**
 25	 * Get a new unique ID.
 26	 *
 27	 * @returns {string} New unique ID.
 28	 */
 29	const generateUniqueId = () => {
 30	  idCounter += 1;
 31	  return `item-${idCounter}`;
 32	};
 33	
 34	/**
 35	 * Extract content from items.
 36	 *
 37	 * @template T
 38	 * @param {Array<{ id: string, content: T }>} items - Items with id and content.
 39	 * @returns {T[]} List of content from items.
 40	 */
 41	const extractContent = <T,>(items: { id: string; content: T }[]): T[] =>
 42	  items.map(({ content }) => content);
 43	
 44	/**
 45	 * Add IDs to items.
 46	 *
 47	 * @param {any[]} items - List of items without IDs.
 48	 * @returns {InputListItem<T>[]} List of items with IDs.
 49	 */
 50	const assignIdsToItems = <T,>(items: T[]): InputListItem<T>[] =>
 51	  items.map((content) => {
 52	    const id = generateUniqueId();
 53	    return { content, id };
 54	  });
 55	
 56	/**
 57	 * Props for InputList component.
 58	 *
 59	 * @template T
 60	 * @typedef {Object} Props
 61	 *
 62	 * @property {T[]} items - List of items.
 63	 * @property {InputListRow<T>} InputRow - Component to render each row.
 64	 * @property {(newList: T[]) => void} onChange - Callback when the list changes.
 65	 * @property {string} [removeIconContent] - Help text for the remove icon tooltip.
 66	 * @property {string} [addButtonText] - Text for the add button.
 67	 */
 68	type InputListProps<T> = {
 69	  items: T[];
 70	  InputRow: InputListRow<T>;
 71	  onChange: (newList: T[]) => void;
 72	  removeIconContent?: string;
 73	  addButtonText?: string;
 74	};
 75	
 76	/**
 77	 * InputList component to handle dynamic list input.
 78	 *
 79	 * @template T
 80	 *
 81	 * @param {InputListProps<T>} props - Props for the component.
 82	 */
 83	export const InputList = <T,>({
 84	  addButtonText = 'Add',
 85	  InputRow,
 86	  items,
 87	  onChange,
 88	  removeIconContent = 'Remove',
 89	}: InputListProps<T>) => {
 90	  const initialStateItems = isEmpty(items) ? [null as unknown as T] : items;
 91	  const [localItems, setLocalItems] = useState<InputListItem<T>[]>(
 92	    assignIdsToItems(initialStateItems),
 93	  );
 94	
 95	  const handleItemChange = (id: string, newContent: T) => {
 96	    const updatedItems = localItems.map(({ content, id: itemId }) => ({
 97	      content: id === itemId ? newContent : content,
 98	      id: itemId,
 99	    }));
100	
101	    setLocalItems(updatedItems);
102	    onChange(extractContent<T>(updatedItems));
103	  };
104	
105	  const handleItemDelete = (id: string) => {
106	    const updatedItems = localItems.filter(({ id: itemId }) => id !== itemId);
107	
108	    setLocalItems(updatedItems);
109	    onChange(extractContent<T>(updatedItems));
110	  };
111	
112	  const handleAddItem = () => {
113	    const newItem: InputListItem<T> = { content: null as unknown as T, id: generateUniqueId() };
114	    const updatedItems = [...localItems, newItem];
115	
116	    setLocalItems(updatedItems);
117	    onChange(extractContent<T>(updatedItems));
118	  };
119	
120	  const isDeleteDisabled = localItems.length === 1;
121	
122	  return (
123	    <>
124	      <DataList aria-label={'input data list'} isCompact>
125	        {localItems.map(({ content, id }) => (
126	          <DataListItem key={id} id={id}>
127	            <DataListItemRow>
128	              <DataListItemCells
129	                dataListCells={[
130	                  <DataListCell key="primary content">
131	                    <InputRow
132	                      value={content}
133	                      onChange={(newValue) => {
134	                        handleItemChange(id, newValue);
135	                      }}
136	                    />
137	                  </DataListCell>,
138	                ]}
139	              />
140	              <DataListAction
141	                id={`mapping_list_item_${id}`}
142	                aria-label={'Actions'}
143	                aria-labelledby=""
144	              >
145	                <Tooltip content={removeIconContent}>
146	                  <Button
147	                    onClick={() => {
148	                      handleItemDelete(id);
149	                    }}
150	                    variant={ButtonVariant.plain}
151	                    aria-label={removeIconContent}
152	                    key="delete-action"
153	                    icon={<MinusCircleIcon />}
154	                    isDisabled={isDeleteDisabled}
155	                  />
156	                </Tooltip>
157	              </DataListAction>
158	            </DataListItemRow>
159	          </DataListItem>
160	        ))}
161	      </DataList>
162	      <Button
163	        className="forklift--input-list-icon"
164	        variant={ButtonVariant.link}
165	        icon={<PlusCircleIcon />}
166	        onClick={handleAddItem}
167	      >
168	        {addButtonText}
169	      </Button>
170	    </>
171	  );
172	};

